import logging
from parsers.log_parser import parse_line

log = logging.getLogger(__name__)


class LogProcessor:
    def __init__(self, output_writer):
        self.writer = output_writer
        self.stats = {'processed': 0, 'errors': 0}

    def process_file(self, path: str):
        with open(path) as f:
            for line_num, line in enumerate(f, 1):
                try:
                    result = parse_line(line)
                    self.writer.write(result)
                    self.stats['processed'] += 1
                except Exception as e:
                    self.stats['errors'] += 1
                    log.warning('Error in %s:%d: %s', path, line_num, e)

    def process_directory(self, dir_path: str):
        import glob
        for path in sorted(glob.glob(f'{dir_path}/*.log')):
            log.info('Processing %s', path)
            self.process_file(path)
        log.info('Done: %d processed, %d errors', self.stats['processed'], self.stats['errors'])
